1	// Spawns qemu-system-riscv64 with -gdb tcp::PORT -S -semihosting and
2	// restores architectural state via the gdbstub before sending `c`. Waits
3	// for QEMU to exit and propagates its process exit code.
4	//
5	// Used by main.cpp when `Simulator::run()` returns kExitHandoffToQemu and
6	// `--qemu-binary` is set.
7	
8	#pragma once
9	
