245	// FP register names match the riscv-64bit-fpu.xml feature; the table
246	// itself is shared with the QEMU plugin via hybrid/reg_names.h.
247	
248	inline constexpr std::array<std::pair<const char*, uint64_t hybrid_state_v1::*>,
249	                            13>
250	  kCsrByName = {{
251	    {"mstatus",  &hybrid_state_v1::mstatus},
252	    {"mepc",     &hybrid_state_v1::mepc},
253	    {"mtvec",    &hybrid_state_v1::mtvec},
254	    {"mcause",   &hybrid_state_v1::mcause},
255	    {"mtval",    &hybrid_state_v1::mtval},
256	    {"mscratch", &hybrid_state_v1::mscratch},
257	    {"medeleg",  &hybrid_state_v1::medeleg},
258	    {"mideleg",  &hybrid_state_v1::mideleg},
259	    {"mip",      &hybrid_state_v1::mip},
260	    {"mie",      &hybrid_state_v1::mie},
261	    {"mcycle",   &hybrid_state_v1::mcycle},
262	    {"minstret", &hybrid_state_v1::minstret},
263	    {"satp",     &hybrid_state_v1::satp},
264	  }};
