268	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
269	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
270	// at `port`, then continues. Caller is responsible for waitpid().
271	inline void restore_state_via_gdbstub(uint16_t port,
272	                                      const hybrid_state_v1& state,
273	                                      pid_t child_pid = -1)
274	{
275	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
276	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
277	                                          child_pid);
278	  spdlog::info("hybrid handback: connected, discovering register map");
279	  gdbstub::Session sess{fd};
280	
281	  const auto reg_map = detail::discover_reg_map(sess);
282	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
283	               reg_map.size());
284	
285	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
286	  // feature is always first.
287	  for (unsigned i = 1; i < 32; ++i) {
288	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
289	    if (reply != "OK")
290	      throw std::runtime_error(
291	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
292	  }
293	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
294	  if (reply != "OK")
295	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
296	
297	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
298	    for (std::size_t i = 0; i < 32; ++i)
299	      detail::try_write_named_u64(sess, reg_map, hybrid_fpr_names[i],
300	                                  state.fpr[i]);
301	
302	  for (const auto& slot : detail::kCsrByName)
303	    detail::try_write_named_u64(sess, reg_map, slot.first,
304	                                state.*(slot.second));
305	
306	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
307	    detail::try_write_named_u64(sess, reg_map, "pmpcfg" + std::to_string(i),
308	                                state.pmpcfg[i]);
309	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
310	    detail::try_write_named_u64(sess, reg_map, "pmpaddr" + std::to_string(i),
311	                                state.pmpaddr[i]);
312	
313	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
314	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
315	    detail::try_write_named_u64(sess, reg_map, "vstart", state.vstart);
316	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
317	    for (uint16_t i = 0; i < 32; ++i) {
318	      const std::string name = "v" + std::to_string(i);
319	      detail::try_write_named_bytes(
320	        sess, reg_map, name,
321	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
322	        vbytes);
323	    }
324	  }
325	
326	  spdlog::info("hybrid handback: continuing target");
327	  sess.cont();
328	}
